// =========================================================================
// Title: Riemann peaks
// Author: iruka
// Source: https://www.shadertoy.com/view/3XKBWz
//
// License: CC BY-NC-SA 3.0 (Shadertoy Default)
//          https://creativecommons.org/licenses/by-nc-sa/3.0/
//
// Description:
// A raymarching shader that visualizes a procedural mathematical landscape 
// generated by an optimized Riemann function. It features a continuous 
// flyover camera, height-based spectral color palettes, and atmospheric 
// depth fog with diffuse and Fresnel lighting effects.
// =========================================================================

#define CAMERA_HEIGHT 3.4
#define CAMERA_TILT - 1.2
#define FLYOVER_SPEED 1.3
#define FOVY 1.8

#define FOG_COLOR vec3(0.00, 0.001, 0.015)
#define SKY_COLOR vec3(0.00, 0.00, 0.01)
#define FOG_DENSITY 0.001

#define N_SUM 14
#define MAX_STEPS 100
#define MAX_DIST 200.0      

// Spectral Color Palette
vec3 getPalette(float t) {
    return 0.5 + 0.5 * cos(6.28318 * (t + vec3(0.26, 0.41, 0.55)));
}

// Optimized Height Function
float riemann(float x, float z) {
    vec2 res = vec2(0.0);
    for (int n = 1; n <= N_SUM; n++) {
        float n2 = float(n * n);
        float phase = n2 * x;
        float shift = float(n) * z;
        res += (1.0/n2) * 2.0 * cos(shift) * vec2(cos(phase) - 1.0, sin(phase));
    }
    return length(res) * 0.5;
}

float map(vec3 p) {
    return (p.y - riemann(p.x, p.z)) * 0.4; 
}

vec3 getNormal(vec3 p) {
    vec2 e = vec2(0.01, 0.0);
    return normalize(vec3(map(p + e.xyy) - map(p - e.xyy),
                          map(p + e.yxy) - map(p - e.yxy),
                          map(p + e.yyx) - map(p - e.yyx)));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;

    // Setup Camera
    vec3 ro = vec3(iTime * FLYOVER_SPEED, CAMERA_HEIGHT, iTime * FLYOVER_SPEED); 
    vec3 fd = normalize(vec3(1.0, CAMERA_TILT, 1.0)); 
    vec3 rt = normalize(cross(vec3(0, 1, 0), fd));
    vec3 rd = normalize(fd + (uv.x * rt + uv.y * cross(fd, rt)) * FOVY);

    // Background Gradient
    vec3 bg = mix(FOG_COLOR, SKY_COLOR, rd.y * 0.5 + 0.5);

    // Raymarching
    float d = 0.0;
    for(int i = 0; i < MAX_STEPS; i++) {
        float s = map(ro + rd * d);
        d += s;
        if(d > MAX_DIST || s < 0.0005) break;
    }

    vec3 col = bg;

    if(d < MAX_DIST) {
        vec3 p = ro + rd * d;
        vec3 n = getNormal(p);

        // Lighting: Diffuse + Fresnel
        float dif = max(dot(n, normalize(vec3(0.5, 0.8, 0.2))), 0.0);
        float fre = pow(clamp(1.0 + dot(rd, n), 0.0, 1.0), 4.0);

        // Final Surface Color
        col = getPalette(p.y * 0.5 + n.y * 0.1) * (dif + 0.3);
        col += fre * vec3(0.4, 0.7, 1.0); // Edge glow
        col *= smoothstep(-0.2, 1.0, p.y); // Vertical shading

        // Fog Apply
        col = mix(bg, col, exp2(-FOG_DENSITY * d * d));
    }

    fragColor = vec4(pow(col, vec3(0.4545)), 1.0);
}

